@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
  background: transparent;
  color: #05042E;
  font-size: 13px;
}

.wrap {
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.section-title {
  font-size: 11px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
  gap: 10px;
}

.card {
  background: #fff;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 10px;
  padding: 14px;
  display: flex;
  flex-direction: column;
  gap: 8px;
  transition: box-shadow 0.15s;
}

.card:hover {
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

.card-top {
  display: flex;
  align-items: center;
  gap: 8px;
}

.icon {
  width: 30px;
  height: 30px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 15px;
  flex-shrink: 0;
}

.type-name {
  font-size: 12px;
  font-weight: 600;
  color: #05042E;
  line-height: 1.3;
}

.total {
  font-size: 26px;
  font-weight: 700;
  line-height: 1;
}

.stats {
  display: flex;
  gap: 6px;
}

.stat {
  flex: 1;
  background: rgba(5, 4, 46, 0.04);
  border-radius: 6px;
  padding: 4px 6px;
  text-align: center;
}

.stat-label {
  font-size: 9px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  display: block;
  margin-bottom: 1px;
}

.stat-value {
  font-size: 12px;
  font-weight: 700;
  color: #05042E;
}

.empty {
  text-align: center;
  padding: 3rem;
  color: #888780;
  font-size: 13px;
}

